## Back-Pressure — Preventing Cascade Failures

Back-pressure is a mechanism where **downstream capacity limits upstream intake**. Without it, a slow database causes a queue to grow without bound, consuming all memory.

```python
import asyncio
from asyncio import Queue, Semaphore

class BackPressuredProcessor:
    def __init__(self, max_concurrent: int = 10, max_queue: int = 100):
        self.semaphore = Semaphore(max_concurrent)
        self.queue: Queue = Queue(maxsize=max_queue)
        self.rejected = 0
        self.processed = 0

    async def submit(self, item: dict) -> bool:
        if self.queue.full():
            self.rejected += 1
            return False  # Signal back-pressure to caller
        await self.queue.put(item)
        return True

    async def process_item(self, item: dict):
        async with self.semaphore:  # limit concurrency
            await asyncio.sleep(0.01)  # simulate DB query
            self.processed += 1

    def stats(self) -> dict:
        total = self.rejected + self.processed
        return {
            "queue_depth": self.queue.qsize(),
            "processed": self.processed,
            "rejected": self.rejected,
            "rejection_rate": self.rejected / max(1, total),
        }
```

### Back-Pressure in HTTP Services

```typescript
import os from "os";

function backPressureMiddleware(maxQueueDepth: number) {
  let queueDepth = 0;

  return (req: any, res: any, next: any) => {
    const loadAvg = os.loadavg()[0] / os.cpus().length;
    queueDepth = Math.max(0, queueDepth - 1); // decay

    if (queueDepth >= maxQueueDepth || loadAvg > 0.9) {
      res.status(503).json({
        error: "Service Temporarily Unavailable",
        retryAfter: 2,
        loadAvg: loadAvg.toFixed(2),
      });
      return;
    }
    queueDepth++;
    next();
  };
}

app.use(backPressureMiddleware(1000));
```

