from concurrent.futures import ThreadPoolExecutor

class BulkheadService:
    def __init__(self):
        # Isolated thread pools — failure in one does not starve others
        self.payment_executor = ThreadPoolExecutor(max_workers=50, thread_name_prefix="pay")
        self.search_executor = ThreadPoolExecutor(max_workers=80, thread_name_prefix="srch")
        self.analytics_executor = ThreadPoolExecutor(max_workers=20, thread_name_prefix="anly")

    def process_payment(self, payload: dict):
        return self.payment_executor.submit(self._do_payment, payload)

    def search(self, query: str):
        return self.search_executor.submit(self._do_search, query)

    def _do_payment(self, payload): pass
    def _do_search(self, query): pass
