### Step 1 — Read Replicas (Handles 80% of cases)

PostgreSQL streaming replication: primary accepts writes, replicas serve reads asynchronously.

```python
import random

class DatabaseRouter:
    def __init__(self, primary_dsn: str, replica_dsns: list):
        self.primary_dsn = primary_dsn
        self.replica_dsns = replica_dsns
        self._replica_index = 0

    def get_write_connection(self) -> str:
        return self.primary_dsn

    def get_read_connection(self, strategy: str = "round_robin") -> str:
        if not self.replica_dsns:
            return self.primary_dsn
        if strategy == "round_robin":
            conn = self.replica_dsns[self._replica_index % len(self.replica_dsns)]
            self._replica_index += 1
            return conn
        return random.choice(self.replica_dsns)

    def execute(self, sql: str, is_write: bool = False) -> str:
        write_ops = ("INSERT", "UPDATE", "DELETE", "CREATE", "DROP")
        if is_write or sql.strip().upper().startswith(write_ops):
            conn = self.get_write_connection()
        else:
            conn = self.get_read_connection()
        return f"Executing on {conn}: {sql[:50]}"

router = DatabaseRouter(
    primary_dsn="postgres://primary:5432/app",
    replica_dsns=[
        "postgres://replica-1:5432/app",
        "postgres://replica-2:5432/app",
    ]
)
print(router.execute("SELECT * FROM users WHERE id = $1"))
# Executing on postgres://replica-1:5432/app: SELECT * FROM users...
print(router.execute("UPDATE users SET last_seen = NOW()", is_write=True))
# Executing on postgres://primary:5432/app: UPDATE users SET last_seen...
```

**Replication lag**: typically **< 100 ms** within a data centre. Can reach seconds under heavy write load. Never rely on replicas for reads requiring read-your-writes consistency.

### Step 2 — Caching at Scale

Cache hit rates compound dramatically. A 95% cache hit rate means the database sees only **5% of original traffic**.

```typescript
// Multi-layer caching: L1 (process memory) -> L2 (Redis) -> DB
import NodeCache from "node-cache";
import Redis from "ioredis";

class MultiLayerCache {
  private l1: NodeCache;   // In-process: ~1ms latency, limited size
  private l2: Redis;       // Redis: ~1-5ms latency, shared across instances

  constructor() {
    this.l1 = new NodeCache({ stdTTL: 60, maxKeys: 10_000 });
    this.l2 = new Redis(process.env.REDIS_URL!);
  }

  async get(key: string): Promise<string | null> {
    const l1Value = this.l1.get<string>(key);
    if (l1Value !== undefined) return l1Value; // L1 hit

    const l2Value = await this.l2.get(key);
    if (l2Value !== null) {
      this.l1.set(key, l2Value, 30); // promote to L1
      return l2Value; // L2 hit
    }

    return null; // Cache miss — caller fetches from DB
  }

  async set(key: string, value: string, ttlSeconds = 300): Promise<void> {
    this.l1.set(key, value, Math.min(ttlSeconds, 60));
    await this.l2.setex(key, ttlSeconds, value);
  }

  async invalidate(key: string): Promise<void> {
    this.l1.del(key);
    await this.l2.del(key);
  }
}
```

### Step 3 — Horizontal Sharding with Consistent Hashing

```python
import hashlib

class ConsistentHashShardRouter:
    def __init__(self, shards: list, virtual_nodes: int = 150):
        self.shards = list(shards)
        self.ring: dict = {}
        self.virtual_nodes = virtual_nodes
        self._build_ring()

    def _hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def _build_ring(self):
        self.ring = {}
        for shard in self.shards:
            for i in range(self.virtual_nodes):
                position = self._hash(f"{shard}:vn{i}")
                self.ring[position] = shard

    def get_shard(self, key: str) -> str:
        if not self.ring:
            raise ValueError("No shards configured")
        position = self._hash(key)
        sorted_positions = sorted(self.ring.keys())
        for p in sorted_positions:
            if p >= position:
                return self.ring[p]
        return self.ring[sorted_positions[0]]

    def add_shard(self, shard: str):
        self.shards.append(shard)
        for i in range(self.virtual_nodes):
            position = self._hash(f"{shard}:vn{i}")
            self.ring[position] = shard
        pct = 100 / len(self.shards)
        print(f"Added {shard}. ~{pct:.0f}% of keys will migrate.")

router = ConsistentHashShardRouter(["db-0", "db-1", "db-2"])
for uid in ["user:123", "user:456", "user:789", "user:1000"]:
    print(f"{uid} -> {router.get_shard(uid)}")

# Adding a 4th shard: only ~25% of keys migrate (vs 100% with mod)
router.add_shard("db-3")
# Added db-3. ~25% of keys will migrate.
```

**Sharding pitfalls**:
- Cross-shard joins become expensive (scatter-gather or denormalise)
- Hotspots: celebrity users on one shard — use sub-sharding or isolation
- Rebalancing: even with consistent hashing, moving data takes time

