### CDN for APIs — Edge Caching Patterns

```python
from functools import wraps
import hashlib

def cdn_cacheable(ttl: int = 300, stale: int = 60, vary: list = None):
    def decorator(func):
        @wraps(func)
        async def wrapper(request, response, *args, **kwargs):
            result = await func(request, response, *args, **kwargs)
            vary_headers = vary or ["Accept-Encoding"]
            response.headers["Cache-Control"] = (
                f"public, max-age={ttl}, stale-while-revalidate={stale}"
            )
            response.headers["Vary"] = ", ".join(vary_headers)
            # Surrogate-Key for targeted purge (Fastly/Varnish)
            surrogate_keys = " ".join([f"endpoint:{func.__name__}"])
            response.headers["Surrogate-Key"] = surrogate_keys
            return result
        return wrapper
    return decorator

async def purge_cdn_by_tag(tag: str, fastly_service_id: str, fastly_key: str):
    import httpx
    async with httpx.AsyncClient() as client:
        response = await client.post(
            f"https://api.fastly.com/service/{fastly_service_id}/purge/{tag}",
            headers={"Fastly-Key": fastly_key},
        )
    return response.status_code == 200

# On product update, purge all CDN caches tagged with that product
async def update_product(product_id: str, data: dict):
    await db.update("products", product_id, data)
    await purge_cdn_by_tag(f"product:{product_id}", FASTLY_SERVICE_ID, FASTLY_KEY)
