# Simple RBAC middleware
def require_role(role):
    def decorator(f):
        def wrapper(*args, **kwargs):
            if current_user.role != role:
                raise Forbidden()
            return f(*args, **kwargs)
        return wrapper
    return decorator

@require_role('admin')
def delete_user(user_id): ...
